import React, { useEffect, useMemo, useState } from 'react';
import {
  ActivityIndicator,
  Alert,
  SafeAreaView,
  StyleSheet,
  Text,
  TextInput,
  TouchableOpacity,
  View,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const AUTH_FLAG_KEY = 'is_authenticated';
const VALID_EMAIL = 'user@example.com';
const VALID_PASSWORD = 'password123';

const rnBiometrics = new ReactNativeBiometrics();

const App = () => {
  const [booting, setBooting] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometryType, setBiometryType] = useState(null);

  useEffect(() => {
    initializeAuth();
  }, []);

  const initializeAuth = async () => {
    try {
      const storedAuth = await AsyncStorage.getItem(AUTH_FLAG_KEY);
      if (storedAuth === 'true') {
        setIsAuthenticated(true);
      }

      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      setBiometricAvailable(available);
      setBiometryType(biometryType || null);

      if (storedAuth !== 'true' && available) {
        setTimeout(() => {
          handleBiometricLogin();
        }, 300);
      }
    } catch (error) {
      Alert.alert('Error', 'Failed to initialize authentication.');
    } finally {
      setBooting(false);
    }
  };

  const saveAuthenticated = async () => {
    await AsyncStorage.setItem(AUTH_FLAG_KEY, 'true');
    setIsAuthenticated(true);
  };

  const clearAuthenticated = async () => {
    await AsyncStorage.removeItem(AUTH_FLAG_KEY);
    setIsAuthenticated(false);
  };

  const handleBiometricLogin = async () => {
    try {
      const { available } = await rnBiometrics.isSensorAvailable();
      if (!available) {
        Alert.alert('Biometrics Unavailable', 'Use your password to log in.');
        return;
      }

      const promptMessage =
        biometryType === ReactNativeBiometrics.FaceID
          ? 'Authenticate with Face ID'
          : biometryType === ReactNativeBiometrics.TouchID
          ? 'Authenticate with Touch ID'
          : 'Authenticate with Biometrics';

      const { success } = await rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Use Password',
      });

      if (success) {
        await saveAuthenticated();
      }
    } catch (error) {}
  };

  const handlePasswordLogin = async ({ email, password }) => {
    if (email === VALID_EMAIL && password === VALID_PASSWORD) {
      await saveAuthenticated();
    } else {
      Alert.alert('Login Failed', 'Invalid email or password.');
    }
  };

  const screen = useMemo(() => {
    if (booting) {
      return <LoadingScreen />;
    }

    if (isAuthenticated) {
      return <HomeScreen onLogout={clearAuthenticated} />;
    }

    return (
      <LoginScreen
        biometricAvailable={biometricAvailable}
        biometryType={biometryType}
        onBiometricLogin={handleBiometricLogin}
        onPasswordLogin={handlePasswordLogin}
      />
    );
  }, [booting, isAuthenticated, biometricAvailable, biometryType]);

  return <SafeAreaView style={styles.container}>{screen}</SafeAreaView>;
};

const LoadingScreen = () => (
  <View style={styles.centered}>
    <ActivityIndicator size="large" />
    <Text style={styles.loadingText}>Checking authentication...</Text>
  </View>
);

const LoginScreen = ({
  biometricAvailable,
  biometryType,
  onBiometricLogin,
  onPasswordLogin,
}) => {
  const [email, setEmail] = useState(VALID_EMAIL);
  const [password, setPassword] = useState(VALID_PASSWORD);

  const biometricLabel =
    biometryType === ReactNativeBiometrics.FaceID
      ? 'Face ID'
      : biometryType === ReactNativeBiometrics.TouchID
      ? 'Touch ID'
      : Platform.OS === 'android'
      ? 'Fingerprint'
      : 'Biometrics';

  return (
    <View style={styles.content}>
      <Text style={styles.title}>Login</Text>
      <Text style={styles.subtitle}>
        {biometricAvailable
          ? `Use ${biometricLabel} or password`
          : 'Biometrics not available. Use password.'}
      </Text>

      <TextInput
        value={email}
        onChangeText={setEmail}
        autoCapitalize="none"
        keyboardType="email-address"
        placeholder="Email"
        style={styles.input}
      />

      <TextInput
        value={password}
        onChangeText={setPassword}
        secureTextEntry
        placeholder="Password"
        style={styles.input}
      />

      <TouchableOpacity
        style={styles.primaryButton}
        onPress={() => onPasswordLogin({ email, password })}
      >
        <Text style={styles.primaryButtonText}>Login with Password</Text>
      </TouchableOpacity>

      {biometricAvailable && (
        <TouchableOpacity style={styles.secondaryButton} onPress={onBiometricLogin}>
          <Text style={styles.secondaryButtonText}>Login with {biometricLabel}</Text>
        </TouchableOpacity>
      )}
    </View>
  );
};

const HomeScreen = ({ onLogout }) => (
  <View style={styles.content}>
    <Text style={styles.title}>Home</Text>
    <Text style={styles.subtitle}>You are authenticated and skipped the login screen.</Text>

    <TouchableOpacity style={styles.primaryButton} onPress={onLogout}>
      <Text style={styles.primaryButtonText}>Logout</Text>
    </TouchableOpacity>
  </View>
);

